<!doctype html><html lang="zh-CN"><head><meta charset="utf-8"><meta name="viewport" content="width=device-width,initial-scale=1"><title>DepartmentIFO</title><script src="/DepartmentIFO/auth-monitor/sdk/js/auth-monitor.min.js"></script><style>
:root{--bg:#f5f7fb;--panel:rgba(255,255,255,.88);--text:#172033;--muted:#667085;--line:#dce5f2;--blue:#007aff;--green:#34c759;--red:#ff3b30;--orange:#ff9500;--side:#0f172a;--shadow:0 18px 45px rgba(15,23,42,.12)}*{box-sizing:border-box}body{margin:0;background:linear-gradient(180deg,#f7faff,#eef3f8);color:var(--text);font-family:-apple-system,BlinkMacSystemFont,"SF Pro Text",Arial,"Microsoft YaHei",sans-serif}button,input,select,textarea{font-family:inherit}.login{min-height:100vh;display:grid;grid-template-columns:1.1fr .9fr}.hero{padding:62px;color:#fff;display:flex;flex-direction:column;justify-content:space-between;background:radial-gradient(circle at 20% 10%,rgba(255,255,255,.28),transparent 20%),linear-gradient(135deg,#0f766e,#007aff 62%,#111827)}.hero h1{font-size:46px;margin:0 0 16px;letter-spacing:0}.hero p{font-size:17px;line-height:1.85;color:#eef6ff;max-width:640px}.heroGrid{display:grid;grid-template-columns:repeat(3,1fr);gap:14px}.heroItem{border:1px solid rgba(255,255,255,.28);border-radius:16px;padding:18px;background:rgba(255,255,255,.13);backdrop-filter:blur(14px);transition:.24s}.heroItem:hover{transform:translateY(-4px);box-shadow:0 18px 42px rgba(0,0,0,.24)}.loginPanel{display:grid;place-items:center;background:rgba(255,255,255,.94);padding:32px}.loginCard{width:min(430px,100%);animation:rise .45s ease}.loginCard h2{font-size:30px;margin:0 0 8px}.hint{color:var(--muted);line-height:1.75}.field{margin:13px 0}.field label{display:block;font-weight:700;margin-bottom:7px}.field input,.field select,.field textarea{width:100%;border:1px solid var(--line);border-radius:12px;background:#fff;padding:12px 13px;font-size:14px;transition:.18s}.field input:focus,.field select:focus,.field textarea:focus{outline:0;border-color:var(--blue);box-shadow:0 0 0 4px rgba(0,122,255,.12)}.btn{border:0;border-radius:12px;padding:10px 14px;background:var(--blue);color:#fff;cursor:pointer;font-weight:700;transition:.16s;text-decoration:none;display:inline-block}.btn:hover{transform:translateY(-1px);box-shadow:0 10px 24px rgba(0,122,255,.23)}.btn:active{transform:scale(.98)}.btn.sub{background:#eef5ff;color:#0057d9}.btn.danger{background:#ffecec;color:#c1121f}.btn.ok{background:#e9f9ef;color:#16843a}.btn.ghost{background:#fff;color:#475467;border:1px solid var(--line)}.btn.block{width:100%;font-size:15px}.err{color:#c1121f;min-height:22px}.app{display:grid;grid-template-columns:264px 1fr;min-height:100vh;transition:.22s}.app.fold{grid-template-columns:78px 1fr}.side{background:rgba(15,23,42,.98);color:#fff;padding:18px 12px;overflow:hidden}.brand{display:flex;align-items:center;gap:10px;font-size:18px;font-weight:900;padding:8px 8px 20px;white-space:nowrap}.logo{width:38px;height:38px;border-radius:13px;background:linear-gradient(135deg,#34c759,#007aff);display:grid;place-items:center;box-shadow:0 10px 24px rgba(0,122,255,.25)}.foldBtn{margin-left:auto;background:#1f2937;border:0;color:#fff;border-radius:10px;padding:7px;cursor:pointer}.nav button{width:100%;border:0;background:transparent;color:#cbd5e1;padding:12px 10px;border-radius:12px;cursor:pointer;text-align:left;font-size:14px;margin:4px 0;display:flex;gap:10px;align-items:center;transition:.18s}.nav button:hover,.nav button.on{background:#1e293b;color:#fff;transform:translateX(3px)}.app.fold .nav span,.app.fold .brand span{display:none}.top{height:66px;background:rgba(255,255,255,.82);backdrop-filter:blur(16px);border-bottom:1px solid var(--line);display:flex;align-items:center;justify-content:space-between;padding:0 24px;position:sticky;top:0;z-index:8}.top h2{margin:0;font-size:19px}.content{padding:22px}.cards{display:grid;grid-template-columns:repeat(5,minmax(140px,1fr));gap:14px;margin-bottom:16px}.card{background:var(--panel);border:1px solid rgba(220,229,242,.85);border-radius:18px;padding:16px;box-shadow:0 1px 2px rgba(15,23,42,.03);transition:.22s;animation:fade .25s ease}.card:hover{box-shadow:var(--shadow);transform:translateY(-3px)}.label{color:var(--muted);font-size:13px}.num{font-size:31px;font-weight:900;margin-top:8px}.grid2{display:grid;grid-template-columns:1.18fr .82fr;gap:16px}.toolbar{display:flex;gap:10px;flex-wrap:wrap;align-items:center;margin-bottom:12px}.toolbar input,.toolbar select{padding:10px 12px;border:1px solid var(--line);border-radius:12px;background:#fff}.tableWrap{overflow:auto;border-radius:18px;border:1px solid var(--line);background:#fff}table{width:100%;border-collapse:collapse;background:#fff}th,td{border-bottom:1px solid #edf2f7;padding:12px;text-align:left;font-size:14px;white-space:nowrap}th{background:#f8fafc;color:#475467}.pill{display:inline-block;border-radius:999px;padding:4px 10px;font-size:12px;background:#eef2ff;color:#3730a3}.pill.ok{background:#e9f9ef;color:#16843a}.pill.off{background:#ffecec;color:#b42318}.pill.warn{background:#fff4e5;color:#9a5b00}.section{display:flex;justify-content:space-between;align-items:center;margin-bottom:12px}.section h3{margin:0}.tree{background:#fff;border:1px solid var(--line);border-radius:20px;padding:22px;overflow:auto}.treeRoot{text-align:center}.treeNode{display:inline-block;min-width:180px;border-radius:16px;padding:14px;background:linear-gradient(180deg,#fff,#f8fbff);border:1px solid var(--line);box-shadow:0 8px 20px rgba(15,23,42,.06);transition:.2s}.treeNode:hover{transform:translateY(-3px);box-shadow:var(--shadow)}.treeChildren{display:flex;gap:18px;align-items:flex-start;justify-content:center;margin-top:28px;position:relative}.treeChildren:before{content:"";position:absolute;top:-14px;left:6%;right:6%;height:1px;background:var(--line)}.deptBox{width:260px}.people{display:flex;flex-direction:column;gap:7px;margin-top:12px;max-height:270px;overflow:auto}.person{display:flex;justify-content:space-between;gap:8px;align-items:center;border:1px solid #e8eef7;background:#fff;border-radius:12px;padding:8px;cursor:pointer;transition:.16s}.person:hover{background:#f0f7ff;transform:translateX(2px)}.heat{display:grid;grid-template-columns:120px repeat(4,1fr);gap:6px;align-items:center}.heatCell{border-radius:10px;padding:12px;text-align:center;font-weight:800;color:#0f172a;background:#eef2f7}.h0{background:#eef2f7}.h1{background:#d9fbe7}.h2{background:#a7f3d0}.h3{background:#5ee0a1}.h4{background:#16a34a;color:#fff}.score{height:9px;background:#e5e7eb;border-radius:999px;overflow:hidden}.score span{display:block;height:100%;background:linear-gradient(90deg,#34c759,#007aff)}.pager{display:flex;gap:8px;justify-content:flex-end;margin-top:12px}.modal{position:fixed;inset:0;background:rgba(15,23,42,.42);display:none;align-items:center;justify-content:center;padding:20px;z-index:30}.modal.show{display:flex}.modalCard{background:rgba(255,255,255,.96);backdrop-filter:blur(18px);border-radius:22px;width:min(920px,100%);max-height:88vh;overflow:auto;padding:22px;box-shadow:0 28px 70px rgba(0,0,0,.24);animation:pop .18s ease}.formGrid{display:grid;grid-template-columns:repeat(2,1fr);gap:12px}.empty{color:var(--muted);padding:20px;text-align:center}@keyframes rise{from{opacity:0;transform:translateY(16px)}to{opacity:1;transform:none}}@keyframes fade{from{opacity:.45;transform:translateY(6px)}to{opacity:1;transform:none}}@keyframes pop{from{opacity:0;transform:scale(.96)}to{opacity:1;transform:scale(1)}}@media(max-width:980px){.login{grid-template-columns:1fr}.app,.app.fold{grid-template-columns:1fr}.side{position:sticky;top:0;z-index:10}.nav{display:grid;grid-template-columns:repeat(3,1fr);gap:4px}.cards{grid-template-columns:repeat(2,1fr)}.grid2{grid-template-columns:1fr}.treeChildren{flex-direction:column;align-items:stretch}.deptBox{width:100%}.heat{grid-template-columns:90px repeat(4,1fr)}}@media(max-width:620px){.content{padding:14px}.cards,.formGrid{grid-template-columns:1fr}.hero{padding:32px}.hero h1{font-size:30px}.heroGrid{grid-template-columns:1fr}.heat{grid-template-columns:1fr 1fr}}
</style></head><body><div id="root"></div><div id="modal" class="modal" onclick="if(event.target.id==='modal')closeModal()"><div id="modalCard" class="modalCard"></div></div><script>
AuthMonitor.init({appId:'member-platform',apiBase:'/DepartmentIFO/auth-monitor/api/v1',autoTrack:true});
const U=s=>JSON.parse('"'+s+'"');
const L={title:U('\\u90e8\\u95e8\\u6210\\u5458\\u7ba1\\u7406\\u5e73\\u53f0'),sub:U('\\u7ec4\\u7ec7\\u6811\\u3001\\u6210\\u5458\\u6863\\u6848\\u3001\\u6743\\u9650\\u6388\\u6743\\u3001\\u8003\\u6838\\u8bc4\\u4ef7\\u548c API \\u76d1\\u63a7\\u4e00\\u4f53\\u5316'),login:U('\\u767b\\u5f55'),account:U('\\u5b66\\u53f7 / \\u8d26\\u53f7'),password:U('\\u5bc6\\u7801'),dashboard:U('\\u6570\\u636e\\u770b\\u677f'),members:U('\\u6210\\u5458\\u6863\\u6848'),org:U('\\u7ec4\\u7ec7\\u67b6\\u6784'),eval:U('\\u8003\\u6838\\u8bc4\\u4ef7'),approval:U('\\u5ba1\\u6279\\u4e2d\\u5fc3'),imports:U('\\u6279\\u91cf\\u5bfc\\u5165'),audit:U('\\u64cd\\u4f5c\\u65e5\\u5fd7'),perm:U('\\u6743\\u9650\\u6388\\u6743'),workflow:U('\\u5de5\\u4f5c\\u6d41'),kpi:U('KPI \\u7ba1\\u7406'),capability:U('\\u80fd\\u529b\\u753b\\u50cf'),logout:U('\\u9000\\u51fa')};
let token=localStorage.getItem('mp_token'),me=null,state={page:'dashboard',fold:false,pageNo:1,limit:20,total:0,members:[],perms:[]};
function has(p){return state.perms.includes('*')||state.perms.includes(p)}function root(){return document.getElementById('root')}function esc(s){return String(s??'').replace(/[&<>"']/g,m=>({'&':'&amp;','<':'&lt;','>':'&gt;','"':'&quot;',"'":'&#39;'}[m]))}function api(path,opt={}){opt.headers=Object.assign({'Content-Type':'application/json','Authorization':'Bearer '+token},opt.headers||{});return fetch('/DepartmentIFO/member-platform/api'+path,opt).then(r=>r.json())}function st(s){return {active:U('\\u5728\\u804c'),suspended:U('\\u505c\\u804c'),retired:U('\\u9000\\u4f11'),trial:U('\\u8bd5\\u7528'),left:U('\\u79bb\\u90e8'),graduated:U('\\u6bd5\\u4e1a'),disabled:U('\\u505c\\u7528')}[s]||s}function pill(s){let c=s==='active'?'ok':s==='suspended'?'warn':'off';return `<span class="pill ${c}">${st(s)}</span>`}
function renderLogin(){root().innerHTML=`<div class="login"><section class="hero"><div><h1>${L.title}</h1><p>${L.sub}</p></div><div class="heroGrid"><div class="heroItem"><b>Auth</b><br>${U('\\u7edf\\u4e00\\u9274\\u6743')}</div><div class="heroItem"><b>Org</b><br>${U('\\u53ef\\u89c6\\u7ec4\\u7ec7\\u6811')}</div><div class="heroItem"><b>Heatmap</b><br>${U('\\u4eba\\u5458\\u70ed\\u529b\\u56fe')}</div></div></section><section class="loginPanel"><div class="loginCard"><h2>${L.login}</h2><p class="hint">${U('\\u8bf7\\u4f7f\\u7528\\u7ba1\\u7406\\u5458\\u8d26\\u53f7\\u6216\\u6210\\u5458\\u5b66\\u53f7\\u767b\\u5f55\\uff0c\\u7cfb\\u7edf\\u4f1a\\u6839\\u636e\\u6743\\u9650\\u52a8\\u6001\\u663e\\u793a\\u529f\\u80fd\\u3002')}</p><div class="field"><label>${L.account}</label><input id="u"></div><div class="field"><label>${L.password}</label><input id="p" type="password"></div><button class="btn block" onclick="loginNow()">${L.login}</button><p class="err" id="loginMsg"></p></div></section></div>`}
function loginNow(){fetch('/DepartmentIFO/member-platform/api/login',{method:'POST',headers:{'Content-Type':'application/json'},body:JSON.stringify({username:u.value,password:p.value})}).then(r=>r.json()).then(d=>{if(d.ok){token=d.access_token;localStorage.setItem('mp_token',token);AuthMonitor.setToken(token);boot()}else loginMsg.textContent=d.message||U('\\u767b\\u5f55\\u5931\\u8d25')})}function boot(){api('/me').then(d=>{if(!d.ok){localStorage.removeItem('mp_token');return renderLogin()}me=d;state.perms=d.permissions||[];shell()})}function logoutNow(){localStorage.removeItem('mp_token');location.reload()}
function navs(){let a=[['dashboard',L.dashboard,'dashboard.view'],['members',L.members,'members.view'],['org',L.org,'organization.view'],['eval',L.eval,'evaluations.view'],['workflow',L.workflow,'workflow.view'],['kpi',L.kpi,'kpi.view'],['capability',L.capability,'capability.view'],['approval',L.approval,'dashboard.view'],['imports',L.imports,'imports.view'],['perm',L.perm,'permissions.grant'],['audit',L.audit,'audit.view']];return a.filter(x=>has(x[2])||has('*')||(x[0]==='members'&&has('members.self'))||(x[0]==='eval'&&has('evaluations.self')))}function navIcon(k){return {dashboard:'D',members:'M',org:'O',eval:'E',workflow:'W',kpi:'K',capability:'C',approval:'A',imports:'I',perm:'P',audit:'L'}[k]||'?'}function title(){return {dashboard:L.dashboard,members:L.members,org:L.org,eval:L.eval,workflow:L.workflow,kpi:L.kpi,capability:L.capability,approval:L.approval,imports:L.imports,audit:L.audit,perm:L.perm}[state.page]||L.dashboard}function shell(){let ns=navs();if(!ns.find(x=>x[0]===state.page))state.page=ns[0]?.[0]||'dashboard';root().innerHTML=`<div class="app ${state.fold?'fold':''}"><aside class="side"><div class="brand"><div class="logo">D</div><span>DepartmentIFO</span><button class="foldBtn" onclick="state.fold=!state.fold;shell()">${state.fold?U('\\u5c55'):U('\\u6536')}</button></div><nav class="nav">${ns.map(x=>`<button class="${state.page===x[0]?'on':''}" onclick="go('${x[0]}')"><b>${navIcon(x[0])}</b><span>${x[1]}</span></button>`).join('')}</nav></aside><main><div class="top"><h2>${title()}</h2><div><span class="pill ok">${esc(me.user.name||me.user.username)}</span> <button class="btn sub" onclick="logoutNow()">${L.logout}</button></div></div><div class="content" id="content"></div></main></div>`;loadPage()}function go(p){state.page=p;state.pageNo=1;shell()}function loadPage(){({dashboard:loadDashboard,members:loadMembers,org:loadOrg,eval:loadEval,workflow:loadWorkflows,kpi:loadKpi,capability:loadCapability,approval:loadApprovals,imports:loadImports,audit:loadAudit,perm:loadPerm}[state.page]||loadDashboard)()}
function heatClass(v,max){let n=max?Math.ceil((v/max)*4):0;return 'h'+Math.max(0,Math.min(4,n))}function loadDashboard(){api('/dashboard/overview').then(d=>{let max=Math.max(...(d.departments||[]).map(x=>+x.c),1);content.innerHTML=`<div class="cards"><div class="card"><div class="label">${U('\\u6210\\u5458\\u603b\\u6570')}</div><div class="num">${d.total}</div></div><div class="card"><div class="label">${U('\\u5728\\u804c')}</div><div class="num">${d.active}</div></div><div class="card"><div class="label">${U('\\u9000\\u4f11')}</div><div class="num">${d.retired}</div></div><div class="card"><div class="label">${U('\\u505c\\u804c')}</div><div class="num">${d.suspended}</div></div><div class="card"><div class="label">${U('\\u5e73\\u5747\\u8003\\u6838')}</div><div class="num">${d.avg_score}</div></div></div><div class="grid2"><div class="card"><h3>${U('\\u90e8\\u95e8\\u4eba\\u5458\\u70ed\\u529b\\u56fe')}</h3><div class="heat"><b>${U('\\u90e8\\u95e8')}</b><b>${U('\\u603b\\u6570')}</b><b>${U('\\u5728\\u804c')}</b><b>${U('\\u5360\\u6bd4')}</b><b>${U('\\u98ce\\u9669')}</b>${(d.departments||[]).map(x=>`<span>${esc(x.name)}</span><div class="heatCell ${heatClass(+x.c,max)}">${x.c}</div><div class="heatCell ${heatClass(+x.active_count,max)}">${x.active_count||0}</div><div class="heatCell">${d.total?Math.round((x.c/d.total)*100):0}%</div><div class="heatCell ${(+x.active_count||0)<3?'h4':'h1'}">${(+x.active_count||0)<3?U('\\u5173\\u6ce8'):U('\\u6b63\\u5e38')}</div>`).join('')}</div></div><div class="card"><h3>${U('\\u6700\\u8fd1\\u64cd\\u4f5c')}</h3>${(d.recent||[]).map(x=>`<p><b>${esc(x.actor)}</b> ${esc(x.action)}<br><span class="label">${x.created_at}</span></p>`).join('')||`<div class="empty">${U('\\u6682\\u65e0\\u8bb0\\u5f55')}</div>`}</div></div>`})}
function params(){return `page=${state.pageNo}&limit=${state.limit}&status=${document.getElementById('sf')?.value||'active'}&q=${encodeURIComponent(document.getElementById('q')?.value||'')}`}function loadMembers(){api('/members?'+params()).then(d=>{state.members=d.data||[];state.total=d.total||0;content.innerHTML=`<div class="toolbar"><input id="q" placeholder="${U('\\u641c\\u7d22\\u59d3\\u540d\\u3001\\u5b66\\u53f7\\u3001\\u90e8\\u95e8\\u3001\\u804c\\u52a1')}"><select id="sf"><option value="active">${U('\\u53ea\\u770b\\u5728\\u804c')}</option><option value="retired">${U('\\u9000\\u4f11\\u4eba\\u5458')}</option><option value="suspended">${U('\\u505c\\u804c\\u4eba\\u5458')}</option><option value="all">${U('\\u5168\\u90e8\\u72b6\\u6001')}</option></select><button class="btn" onclick="state.pageNo=1;loadMembers()">${U('\\u641c\\u7d22')}</button>${has('members.sensitive')||has('*')?`<button class="btn sub" onclick="openMemberForm()">${U('\\u65b0\\u589e\\u6210\\u5458')}</button>`:''}<a class="btn sub" href="/DepartmentIFO/member-platform/api/export/members" target="_blank">${U('\\u5bfc\\u51fa')}</a></div><div class="tableWrap"><table><thead><tr><th>${U('\\u59d3\\u540d')}</th><th>${U('\\u5b66\\u53f7')}</th><th>${U('\\u90e8\\u95e8')}</th><th>${U('\\u804c\\u52a1')}</th><th>${U('\\u72b6\\u6001')}</th><th>${U('\\u64cd\\u4f5c')}</th></tr></thead><tbody>${state.members.map(m=>`<tr><td><a href="javascript:viewMember(${m.id})">${esc(m.name)}</a></td><td>${esc(m.stuno)}</td><td>${esc(m.bm)}</td><td>${esc(m.posts)}</td><td>${pill(m.status)}</td><td><button class="btn sub" onclick="viewMember(${m.id})">${U('\\u8be6\\u60c5')}</button> ${has('members.status')||has('*')?`<button class="btn danger" onclick="setStatus(${m.id},'suspend')">${U('\\u505c\\u804c')}</button><button class="btn ghost" onclick="setStatus(${m.id},'retire')">${U('\\u9000\\u4f11')}</button><button class="btn ok" onclick="setStatus(${m.id},'restore')">${U('\\u6062\\u590d')}</button>`:''}</td></tr>`).join('')}</tbody></table></div><div class="pager"><span>${U('\\u7b2c')} ${state.pageNo} ${U('\\u9875')} / ${U('\\u5171')} ${state.total} ${U('\\u6761')}</span><button class="btn sub" onclick="state.pageNo=Math.max(1,state.pageNo-1);loadMembers()">${U('\\u4e0a\\u4e00\\u9875')}</button><button class="btn sub" onclick="state.pageNo++;loadMembers()">${U('\\u4e0b\\u4e00\\u9875')}</button></div>`})}function setStatus(id,a){api('/members/'+id+'/'+a,{method:'POST',body:'{}'}).then(loadMembers)}
function viewMember(id){api('/members/'+id).then(d=>{if(!d.ok)return alert(d.message);let m=d.member;modal(`<h3>${esc(m.name)}${U('\\u7684\\u5b8c\\u6574\\u6863\\u6848')}</h3><div class="cards"><div class="card"><div class="label">${U('\\u5b66\\u53f7')}</div><b>${esc(m.stuno)}</b></div><div class="card"><div class="label">${U('\\u90e8\\u95e8')}</div><b>${esc(m.bm)}</b></div><div class="card"><div class="label">${U('\\u804c\\u52a1')}</div><b>${esc(m.posts)}</b></div><div class="card"><div class="label">${U('\\u72b6\\u6001')}</div>${pill(m.status)}</div></div><div class="grid2"><div class="card"><h3>${U('\\u57fa\\u7840\\u4fe1\\u606f')}</h3><p>${U('\\u7535\\u8bdd')} ${U('\\uff1a')} ${esc(m.phone)}</p><p>${U('\\u90ae\\u7bb1')} ${U('\\uff1a')} ${esc(m.email)}</p><p>${U('\\u6807\\u7b7e')} ${U('\\uff1a')} ${esc(m.tags)}</p><p>${U('\\u5907\\u6ce8')} ${U('\\uff1a')} ${esc(m.remark)}</p></div><div class="card"><h3>${U('\\u57f9\\u517b\\u6863\\u6848')}</h3><p>${esc(d.profile?.training_record||U('\\u6682\\u65e0\\u57f9\\u517b\\u8bb0\\u5f55'))}</p></div></div><div class="card"><h3>${U('\\u8003\\u6838\\u8bb0\\u5f55')}</h3>${(d.evaluations||[]).map(e=>`<p>${e.created_at} ${U('\\uff1a')} ${e.total_score} ${U('\\u5206')} / ${esc(e.level)} / ${esc(e.comment)}</p>`).join('')||U('\\u6682\\u65e0\\u8003\\u6838\\u8bb0\\u5f55')}</div><button class="btn sub" onclick="closeModal()">${U('\\u5173\\u95ed')}</button>`)})}
function openMemberForm(){modal(`<h3>${U('\\u65b0\\u589e\\u6210\\u5458')}</h3><div class="formGrid"><div class="field"><label>${U('\\u59d3\\u540d')}</label><input id="mn"></div><div class="field"><label>${U('\\u5b66\\u53f7')}</label><input id="ms"></div><div class="field"><label>${U('\\u90e8\\u95e8')}</label><input id="mb"></div><div class="field"><label>${U('\\u804c\\u52a1')}</label><input id="mpo"></div></div><button class="btn" onclick="saveMember()">${U('\\u4fdd\\u5b58')}</button> <button class="btn sub" onclick="closeModal()">${U('\\u53d6\\u6d88')}</button>`)}function saveMember(){api('/members',{method:'POST',body:JSON.stringify({name:mn.value,stuno:ms.value,bm:mb.value,posts:mpo.value})}).then(()=>{closeModal();loadMembers()})}
function loadOrg(){api('/organization/summary').then(d=>{let by={};(d.members||[]).forEach(m=>{(by[m.department_id||'none']||(by[m.department_id||'none']=[])).push(m)});content.innerHTML=`<div class="section"><h3>${U('\\u53ef\\u89c6\\u5316\\u7ec4\\u7ec7\\u6811')}</h3>${has('organization.manage')||has('*')?`<button class="btn" onclick="openDeptForm()">${U('\\u65b0\\u589e\\u90e8\\u95e8')}</button>`:''}</div><div class="tree"><div class="treeRoot"><div class="treeNode"><b>DepartmentIFO</b><br><span class="label">${U('\\u5927\\u5b66\\u751f\\u7f51\\u7edc\\u4fe1\\u606f\\u4e2d\\u5fc3')}</span></div><div class="treeChildren">${(d.departments||[]).map(dep=>`<div class="treeNode deptBox"><b>${esc(dep.name)}</b><br><span class="pill">${U('\\u603b')} ${dep.member_count}</span> <span class="pill ok">${U('\\u5728\\u804c')} ${dep.active_count||0}</span><div class="people">${(by[dep.id]||[]).slice(0,28).map(m=>`<div class="person" onclick="viewMember(${m.id})"><span>${esc(m.name)}</span><small>${esc(m.posts)} / ${st(m.status)}</small></div>`).join('')||`<span class="label">${U('\\u6682\\u65e0\\u6210\\u5458')}</span>`}</div></div>`).join('')}</div></div></div>`})}function openDeptForm(){modal(`<h3>${U('\\u65b0\\u589e\\u90e8\\u95e8')}</h3><div class="field"><label>${U('\\u90e8\\u95e8\\u540d\\u79f0')}</label><input id="dn"></div><button class="btn" onclick="api('/departments',{method:'POST',body:JSON.stringify({name:dn.value})}).then(()=>{closeModal();loadOrg()})">${U('\\u4fdd\\u5b58')}</button> <button class="btn sub" onclick="closeModal()">${U('\\u53d6\\u6d88')}</button>`)}
function loadEval(){Promise.all([api('/evaluations'),api('/evaluations/summary'),api('/members?status=active&limit=100')]).then(([e,s,m])=>{state.members=m.data||[];content.innerHTML=`<div class="section"><h3>${L.eval}</h3>${has('evaluations.manage')||has('*')?`<button class="btn" onclick="openEvalForm()">${U('\\u65b0\\u589e\\u8bc4\\u4ef7')}</button>`:''}</div><div class="grid2"><div class="card"><h3>${U('\\u90e8\\u95e8\\u8bc4\\u4ef7\\u70ed\\u529b')}</h3><div class="heat"><b>${U('\\u90e8\\u95e8')}</b><b>${U('\\u5df2\\u8bc4')}</b><b>${U('\\u5747\\u5206')}</b><b>${U('\\u7b49\\u7ea7')}</b><b>${U('\\u5173\\u6ce8')}</b>${(s.data||[]).map(x=>{let avg=+(x.avg_score||0);return `<span>${esc(x.department)}</span><div class="heatCell ${heatClass(+x.evaluated,10)}">${x.evaluated}</div><div class="heatCell ${heatClass(avg,100)}">${avg}</div><div class="heatCell">${avg>=90?'A':avg>=80?'B':avg>=70?'C':'-'}</div><div class="heatCell ${avg&&avg<70?'h4':'h1'}">${avg&&avg<70?U('\\u8ddf\\u8fdb'):U('\\u6b63\\u5e38')}</div>`}).join('')}</div></div><div class="card"><h3>${U('\\u8bc4\\u4ef7\\u8bf4\\u660e')}</h3><p>${U('\\u5de5\\u4f5c\\u8d28\\u91cf\\u3001\\u7eaa\\u5f8b\\u6267\\u884c\\u3001\\u534f\\u4f5c\\u8d21\\u732e\\u3001\\u6210\\u957f\\u8868\\u73b0\\u5404 25 \\u5206\\uff0c\\u8bb0\\u5f55\\u8fdb\\u5165\\u4e2a\\u4eba\\u6863\\u6848\\u3002')}</p></div></div><div class="tableWrap" style="margin-top:16px"><table><thead><tr><th>${U('\\u6210\\u5458')}</th><th>${U('\\u90e8\\u95e8')}</th><th>${U('\\u804c\\u52a1')}</th><th>${U('\\u603b\\u5206')}</th><th>${U('\\u7b49\\u7ea7')}</th><th>${U('\\u8bc4\\u4ef7\\u4eba')}</th><th>${U('\\u65f6\\u95f4')}</th></tr></thead><tbody>${(e.data||[]).map(x=>`<tr><td>${esc(x.member_name)}</td><td>${esc(x.bm)}</td><td>${esc(x.posts)}</td><td>${x.total_score}</td><td><span class="pill ok">${esc(x.level)}</span></td><td>${esc(x.evaluator)}</td><td>${x.created_at}</td></tr>`).join('')}</tbody></table></div>`})}function openEvalForm(){modal(`<h3>${U('\\u65b0\\u589e\\u8003\\u6838\\u8bc4\\u4ef7')}</h3><div class="field"><label>${U('\\u6210\\u5458')}</label><select id="em">${state.members.map(m=>`<option value="${m.id}">${esc(m.name)} - ${esc(m.stuno)} - ${esc(m.bm)}</option>`).join('')}</select></div><div class="formGrid"><div class="field"><label>${U('\\u5de5\\u4f5c\\u8d28\\u91cf')}</label><input id="s1" type="number" value="22"></div><div class="field"><label>${U('\\u7eaa\\u5f8b\\u6267\\u884c')}</label><input id="s2" type="number" value="22"></div><div class="field"><label>${U('\\u534f\\u4f5c\\u8d21\\u732e')}</label><input id="s3" type="number" value="22"></div><div class="field"><label>${U('\\u6210\\u957f\\u8868\\u73b0')}</label><input id="s4" type="number" value="22"></div></div><div class="field"><label>${U('\\u8bc4\\u8bed')}</label><textarea id="ec"></textarea></div><button class="btn" onclick="api('/evaluations',{method:'POST',body:JSON.stringify({member_id:em.value,work_score:s1.value,discipline_score:s2.value,collaboration_score:s3.value,growth_score:s4.value,comment:ec.value})}).then(()=>{closeModal();loadEval()})">${U('\\u4fdd\\u5b58')}</button> <button class="btn sub" onclick="closeModal()">${U('\\u53d6\\u6d88')}</button>`)}
function loadPerm(){Promise.all([api('/members?status=active&limit=100'),api('/permissions/catalog')]).then(([m,p])=>{content.innerHTML=`<div class="card"><h3>${L.perm}</h3><p>${U('\\u8d85\\u7ea7\\u7ba1\\u7406\\u5458\\u53ef\\u4ee5\\u7ed9\\u6307\\u5b9a\\u6210\\u5458\\u6388\\u4e88\\u67d0\\u4e00\\u9879\\u529f\\u80fd\\u6743\\u9650\\uff0c\\u6240\\u6709\\u6388\\u6743\\u64cd\\u4f5c\\u90fd\\u5199\\u5165\\u5ba1\\u8ba1\\u65e5\\u5fd7\\u3002')}</p><div class="formGrid"><div class="field"><label>${U('\\u6210\\u5458')}</label><select id="pm">${(m.data||[]).map(x=>`<option value="${x.id}">${esc(x.name)} - ${esc(x.bm)} - ${esc(x.posts)}</option>`).join('')}</select></div><div class="field"><label>${U('\\u6743\\u9650')}</label><select id="pp">${(p.data||[]).map(x=>`<option>${x}</option>`).join('')}</select></div></div><button class="btn" onclick="api('/permissions/grant',{method:'POST',body:JSON.stringify({member_id:pm.value,permission:pp.value,effect:'allow',scope_type:'global'})}).then(()=>alert('${U('\\u6388\\u6743\\u5b8c\\u6210')}'))">${U('\\u6388\\u6743')}</button></div>`})}
function loadWorkflows(){Promise.all([api('/workflows/overview'),api('/workflows')]).then(([o,w])=>{let stat={};(o.status||[]).forEach(x=>stat[x.status]=x.count);content.innerHTML=`<div class="cards"><div class="card"><div class="label">${U('\\u8fd0\\u884c\\u4e2d')}</div><div class="num">${stat.running||0}</div></div><div class="card"><div class="label">${U('\\u5df2\\u5b8c\\u6210')}</div><div class="num">${stat.approved||0}</div></div><div class="card"><div class="label">${U('\\u5df2\\u9a73\\u56de')}</div><div class="num">${stat.rejected||0}</div></div><div class="card"><div class="label">${U('\\u6a21\\u677f\\u6570')}</div><div class="num">${(o.templates||[]).length}</div></div><div class="card"><div class="label">${U('\\u5f85\\u529e\\u6570')}</div><div class="num">${(o.tasks||[]).filter(x=>x.status==='pending').length}</div></div></div><div class="grid2"><div class="card"><div class="section"><h3>${U('\\u6807\\u51c6\\u6d41\\u7a0b\\u6a21\\u677f')}</h3>${has('workflow.manage')||has('*')?`<button class="btn" onclick="openWorkflowStart()">${U('\\u53d1\\u8d77\\u6d41\\u7a0b')}</button>`:''}</div>${(o.templates||[]).map(t=>`<div class="person"><span><b>${esc(t.name)}</b><br><small>${esc(t.description)}</small></span><span class="pill">${U('\\u4f7f\\u7528')} ${t.used_count||0}</span></div>`).join('')}</div><div class="card"><h3>${U('\\u5f85\\u529e\\u4efb\\u52a1')}</h3>${(o.tasks||[]).slice(0,12).map(t=>`<p><b>${esc(t.step_name)}</b> / ${esc(t.title)}<br><span class="label">${esc(t.assignee_role)} / ${esc(t.status)} / ${esc(t.due_at||'')}</span></p>`).join('')||`<div class="empty">${U('\\u6682\\u65e0\\u5f85\\u529e')}</div>`}</div></div><div class="tableWrap" style="margin-top:16px"><table><thead><tr><th>${U('\\u6d41\\u7a0b')}</th><th>${U('\\u6a21\\u677f')}</th><th>${U('\\u7533\\u8bf7\\u4eba')}</th><th>${U('\\u5f53\\u524d\\u8282\\u70b9')}</th><th>${U('\\u72b6\\u6001')}</th><th>${U('\\u64cd\\u4f5c')}</th></tr></thead><tbody>${(w.data||[]).map(x=>`<tr><td>${esc(x.title)}</td><td>${esc(x.template_name)}</td><td>${esc(x.applicant_stuno)}</td><td>${x.current_step}</td><td><span class="pill">${esc(x.status)}</span></td><td>${has('workflow.manage')||has('*')?`<button class="btn ok" onclick="decideWorkflow(${x.id},'approve')">${U('\\u901a\\u8fc7')}</button> <button class="btn danger" onclick="decideWorkflow(${x.id},'reject')">${U('\\u9a73\\u56de')}</button>`:''}</td></tr>`).join('')}</tbody></table></div>`;window.workflowTemplates=w.templates||[]})}
function openWorkflowStart(){modal(`<h3>${U('\\u53d1\\u8d77\\u5de5\\u4f5c\\u6d41')}</h3><div class="field"><label>${U('\\u6d41\\u7a0b\\u6a21\\u677f')}</label><select id="wtpl">${(window.workflowTemplates||[]).map(t=>`<option value="${t.id}">${esc(t.name)}</option>`).join('')}</select></div><div class="field"><label>${U('\\u6807\\u9898')}</label><input id="wtitle"></div><button class="btn" onclick="api('/workflows/start',{method:'POST',body:JSON.stringify({template_id:wtpl.value,title:wtitle.value})}).then(()=>{closeModal();loadWorkflows()})">${U('\\u63d0\\u4ea4')}</button> <button class="btn sub" onclick="closeModal()">${U('\\u53d6\\u6d88')}</button>`)}function decideWorkflow(id,d){api('/workflows/'+id+'/'+d,{method:'POST',body:JSON.stringify({note:''})}).then(loadWorkflows)}
function loadKpi(){api('/kpi/overview').then(d=>{let max=Math.max(...(d.departments||[]).map(x=>+x.avg_score),100);content.innerHTML=`<div class="cards"><div class="card"><div class="label">${U('\\u5f53\\u524d\\u5468\\u671f')}</div><b>${esc(d.cycle?.name||'')}</b></div><div class="card"><div class="label">${U('\\u90e8\\u95e8\\u6570')}</div><div class="num">${(d.departments||[]).length}</div></div><div class="card"><div class="label">${U('\\u6307\\u6807\\u6570')}</div><div class="num">${(d.metrics||[]).length}</div></div><div class="card"><div class="label">${U('\\u4f18\\u79c0\\u6210\\u5458')}</div><div class="num">${(d.top||[]).filter(x=>+x.avg_score>=90).length}</div></div><div class="card"><div class="label">${U('\\u5f85\\u8ddf\\u8fdb')}</div><div class="num">${(d.risk||[]).length}</div></div></div><div class="grid2"><div class="card"><h3>${U('\\u90e8\\u95e8 KPI \\u70ed\\u529b\\u56fe')}</h3><div class="heat"><b>${U('\\u90e8\\u95e8')}</b><b>${U('\\u4eba\\u6570')}</b><b>${U('\\u5747\\u5206')}</b><b>${U('\\u7b49\\u7ea7')}</b><b>${U('\\u72b6\\u6001')}</b>${(d.departments||[]).map(x=>{let a=+x.avg_score||0;return `<span>${esc(x.department)}</span><div class="heatCell">${x.member_count}</div><div class="heatCell ${heatClass(a,max)}">${a}</div><div class="heatCell">${a>=90?'A':a>=80?'B':a>=70?'C':'D'}</div><div class="heatCell ${a<75?'h4':'h2'}">${a<75?U('\\u8ddf\\u8fdb'):U('\\u7a33\\u5b9a')}</div>`}).join('')}</div></div><div class="card"><h3>${U('\\u6307\\u6807\\u7ed3\\u6784')}</h3>${(d.metrics||[]).map(m=>`<p><b>${esc(m.name)}</b> <span class="label">${esc(m.dimension)} / ${m.weight}</span><div class="score"><span style="width:${Math.min(100,+m.avg_score||0)}%"></span></div></p>`).join('')}</div></div><div class="grid2" style="margin-top:16px"><div class="card"><h3>${U('\\u9ad8\\u8868\\u73b0\\u6210\\u5458')}</h3>${(d.top||[]).map(x=>`<div class="person"><span>${esc(x.name)} / ${esc(x.bm)}</span><b>${x.avg_score}</b></div>`).join('')}</div><div class="card"><h3>${U('\\u9700\\u8981\\u8ddf\\u8fdb')}</h3>${(d.risk||[]).map(x=>`<div class="person"><span>${esc(x.name)} / ${esc(x.bm)}</span><b>${x.avg_score}</b></div>`).join('')||`<div class="empty">${U('\\u6682\\u65e0\\u98ce\\u9669')}</div>`}</div></div>`})}
function loadCapability(){api('/capabilities/overview').then(d=>{let dims=[...new Set((d.departments||[]).map(x=>x.dimension))];let deps=[...new Set((d.departments||[]).map(x=>x.department))];let val=(dep,dim)=>((d.departments||[]).find(x=>x.department===dep&&x.dimension===dim)||{}).avg_score||0;content.innerHTML=`<div class="card"><h3>${U('\\u90e8\\u95e8\\u80fd\\u529b\\u77e9\\u9635')}</h3><div class="heat" style="grid-template-columns:140px repeat(${Math.max(1,dims.length)},1fr)"><b>${U('\\u90e8\\u95e8')}</b>${dims.map(x=>`<b>${esc(x)}</b>`).join('')}${deps.map(dep=>`<span>${esc(dep)}</span>${dims.map(dim=>{let v=+val(dep,dim);return `<div class="heatCell ${heatClass(v,100)}">${v}</div>`}).join('')}`).join('')}</div></div><div class="tableWrap" style="margin-top:16px"><table><thead><tr><th>${U('\\u6210\\u5458')}</th><th>${U('\\u90e8\\u95e8')}</th><th>${U('\\u804c\\u52a1')}</th><th>${U('\\u80fd\\u529b\\u6982\\u89c8')}</th><th>${U('\\u5e73\\u5747')}</th></tr></thead><tbody>${(d.people||[]).map(p=>`<tr><td>${esc(p.name)}</td><td>${esc(p.bm)}</td><td>${esc(p.posts)}</td><td>${String(p.capability_map||'').split('|').map(i=>`<span class="pill">${esc(i)}</span>`).join(' ')}</td><td>${p.avg_score||''}</td></tr>`).join('')}</tbody></table></div>`})}function loadApprovals(){api('/approvals').then(d=>{content.innerHTML=`<div class="tableWrap"><table><thead><tr><th>${U('\\u6807\\u9898')}</th><th>${U('\\u7c7b\\u578b')}</th><th>${U('\\u7533\\u8bf7\\u4eba')}</th><th>${U('\\u72b6\\u6001')}</th><th>${U('\\u65f6\\u95f4')}</th></tr></thead><tbody>${(d.data||[]).map(x=>`<tr><td>${esc(x.title)}</td><td>${esc(x.type)}</td><td>${esc(x.applicant_stuno)}</td><td><span class="pill">${x.status}</span></td><td>${x.created_at}</td></tr>`).join('')}</tbody></table></div>`})}function loadImports(){content.innerHTML=`<div class="card"><h3>${L.imports}</h3><p>${U('\\u652f\\u6301 CSV / XLS / XLSX\\uff0c\\u7cfb\\u7edf\\u4f1a\\u5148\\u9884\\u89c8\\u5e76\\u6821\\u9a8c\\u91cd\\u590d\\u5b66\\u53f7\\u3001\\u7a7a\\u59d3\\u540d\\u548c\\u7a7a\\u5b66\\u53f7\\uff0c\\u786e\\u8ba4\\u540e\\u518d\\u5165\\u5e93\\u3002')}</p><input type="file" id="file"><button class="btn" onclick="previewImport()">${U('\\u4e0a\\u4f20\\u9884\\u89c8')}</button><pre id="importResult"></pre></div>`}function previewImport(){let fd=new FormData();fd.append('file',file.files[0]);fetch('/DepartmentIFO/member-platform/api/imports/preview',{method:'POST',headers:{'Authorization':'Bearer '+token},body:fd}).then(r=>r.json()).then(d=>importResult.textContent=JSON.stringify(d,null,2))}function loadAudit(){api('/audit-logs').then(d=>{content.innerHTML=`<div class="tableWrap"><table><thead><tr><th>${U('\\u64cd\\u4f5c\\u4eba')}</th><th>${U('\\u52a8\\u4f5c')}</th><th>${U('\\u5bf9\\u8c61')}</th><th>${U('\\u8be6\\u60c5')}</th><th>${U('\\u65f6\\u95f4')}</th></tr></thead><tbody>${(d.data||[]).map(x=>`<tr><td>${esc(x.actor)}</td><td>${esc(x.action)}</td><td>${esc(x.target_type)} #${esc(x.target_id)}</td><td>${esc(x.detail)}</td><td>${x.created_at}</td></tr>`).join('')}</tbody></table></div>`})}
function modal(html){modalCard.innerHTML=html;document.getElementById('modal').classList.add('show')}function closeModal(){document.getElementById('modal').classList.remove('show')}if(token)boot();else renderLogin();
</script></body></html>
